/* clavier math */
const MKS=[
  {l:"a/b",x:"a/b"},{l:"√",x:"√"},{l:"²",x:"²"},{l:"³",x:"³"},
  {l:"∫",x:"∫"},{l:"Σ",x:"Σ"},{l:"lim",x:"lim "},{l:"f′",x:"f′"},
  {l:"sin",x:"sin"},{l:"cos",x:"cos"},{l:"tan",x:"tan"},{l:"ln",x:"ln"},
  {l:"π",x:"π"},{l:"∞",x:"∞"},{l:"≤",x:"≤"},{l:"≥",x:"≥"},
  {l:"≠",x:"≠"},{l:"→",x:"→"},{l:"∈",x:"∈"},{l:"±",x:"±"},
  {l:"ℝ",x:"ℝ"},{l:"ℕ",x:"ℕ"},{l:"ℤ",x:"ℤ"},{l:"∩",x:"∩"},{l:"∪",x:"∪"},
  {l:"α",x:"α"},{l:"β",x:"β"},{l:"θ",x:"θ"},{l:"Δ",x:"Δ"},{l:"λ",x:"λ"},
  {l:"ₙ",x:"ₙ"},{l:"₀",x:"₀"},{l:"₁",x:"₁"},{l:"₂",x:"₂"},
];

function MathKbd({onInsert,onClose}){
  return(
    <div style={{background:"linear-gradient(160deg,#090e1c,#0d1628)",border:"1px solid "+K.bd,borderRadius:13,padding:13,boxShadow:"0 20px 60px rgba(0,0,0,0.7)",direction:"rtl"}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:9}}>
        <span style={{color:K.ac,fontWeight:800,fontSize:11,fontFamily:"'Cairo',sans-serif"}}>⌨️ الرموز الرياضية</span>
        <button onClick={onClose} style={{background:"none",border:"none",color:K.tm,cursor:"pointer",fontSize:15}}>✕</button>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(8,1fr)",gap:3,marginBottom:7}}>
        {MKS.map((k,i)=>(
          <button key={i} onClick={()=>onInsert(k.x)}
            style={{background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:6,padding:"7px 3px",color:K.ts,fontSize:13,cursor:"pointer",fontFamily:"Georgia,serif"}}
            onMouseEnter={e=>{e.currentTarget.style.background=K.ad;e.currentTarget.style.color=K.ac;}}
            onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,0.04)";e.currentTarget.style.color=K.ts;}}
          >{k.l}</button>
        ))}
      </div>
      <div style={{height:1,background:"rgba(255,255,255,0.05)",margin:"5px 0 7px"}}/>
      <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>
        {"abcdefghijklmnopqrstuvwxyz0123456789()=+,./_".split("").map((c,i)=>(
          <button key={i} onClick={()=>onInsert(c)}
            style={{background:"rgba(255,255,255,0.03)",border:"1px solid "+K.bd,borderRadius:5,padding:"5px 5px",color:K.tm,fontSize:11,cursor:"pointer",fontFamily:"monospace"}}
            onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,0.09)";}}
            onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,0.03)";}}
          >{c}</button>
        ))}
        <button onClick={()=>onInsert("\n")} style={{background:"rgba(255,255,255,0.03)",border:"1px solid "+K.bd,borderRadius:5,padding:"5px 8px",color:K.tm,fontSize:11,cursor:"pointer"}}>↵</button>
        <button onClick={()=>onInsert("BACK")} style={{background:K.rd,border:"1px solid rgba(255,82,82,0.2)",borderRadius:5,padding:"5px 9px",color:K.re,fontSize:12,cursor:"pointer",fontWeight:700}}>⌫</button>
        <button onClick={()=>onInsert("CLR")} style={{background:"rgba(255,82,82,0.05)",border:"1px solid rgba(255,82,82,0.12)",borderRadius:5,padding:"5px 8px",color:K.re+"80",fontSize:10,cursor:"pointer",fontFamily:"'Cairo',sans-serif"}}>محو</button>
      </div>
    </div>
  );
}

